144	fn with_budget<R>(budget: Budget, f: impl FnOnce() -> R) -> R {
145	    struct ResetGuard {
146	        prev: Budget,
147	    }
148	
149	    impl Drop for ResetGuard {
150	        fn drop(&mut self) {
151	            let _ = context::budget(|cell| {
152	                cell.set(self.prev);
153	            });
154	        }
155	    }
